	test(13, CMPLX(90.01, nan("")), CMPLX(nan(""), nan("")), CMPLX(nan(""), nan("")), CMPLX(nan(""), nan("")), 0);
	test(14, CMPLX(-12.34, nan("")), CMPLX(nan(""), nan("")), CMPLX(nan(""), nan("")), CMPLX(nan(""), nan("")), 0);
	test(15, CMPLX(nan(""), nan("")), CMPLX(nan(""), nan("")), CMPLX(nan(""), nan("")), CMPLX(nan(""), nan("")), 0);
	test(16, CMPLX(strtod("inf", NULL), nan("")), CMPLX(nan(""), nan("")), CMPLX(nan(""), nan("")), CMPLX(nan(""), nan("")), 0);
	test(17, CMPLX(strtod("-inf", NULL), nan("")), CMPLX(nan(""), nan("")), CMPLX(nan(""), nan("")), CMPLX(nan(""), nan("")), 0);
	test(18, CMPLX(0.0, nan("")), CMPLX(-0x0.0000000000001p-1022, nan("")), CMPLX(0x0.0p+0, nan("")), CMPLX(0x0.0000000000001p-1022, nan("")), 0);
	test(19, CMPLX(90.01, strtod("inf", NULL)), CMPLX(strtod("inf", NULL), strtod("-inf", NULL)), CMPLX(strtod("inf", NULL), strtod("-inf", NULL)), CMPLX(strtod("inf", NULL), strtod("-inf", NULL)), 0);
	test(20, CMPLX(-12.34, strtod("inf", NULL)), CMPLX(strtod("inf", NULL), strtod("inf", NULL)), CMPLX(strtod("inf", NULL), strtod("inf", NULL)), CMPLX(strtod("inf", NULL), strtod("inf", NULL)), 0);
	test(21, CMPLX(nan(""), strtod("inf", NULL)), CMPLX(nan(""), strtod("inf", NULL)), CMPLX(nan(""), strtod("inf", NULL)), CMPLX(nan(""), strtod("inf", NULL)), 0 | MF_ANYSIGN2);
	test(22, CMPLX(strtod("inf", NULL), strtod("inf", NULL)), CMPLX(nan(""), strtod("inf", NULL)), CMPLX(nan(""), strtod("inf", NULL)), CMPLX(nan(""), strtod("inf", NULL)), 0 | MF_ANYSIGN2);
	test(23, CMPLX(strtod("-inf", NULL), strtod("inf", NULL)), CMPLX(nan(""), strtod("inf", NULL)), CMPLX(nan(""), strtod("inf", NULL)), CMPLX(nan(""), strtod("inf", NULL)), 0 | MF_ANYSIGN2);
	test(24, CMPLX(0.0, strtod("inf", NULL)), CMPLX(-0x0.0000000000001p-1022, strtod("inf", NULL)), CMPLX(0x0.0p+0, strtod("inf", NULL)), CMPLX(0x0.0000000000001p-1022, strtod("inf", NULL)), 0);
	test(25, CMPLX(90.01, strtod("-inf", NULL)), CMPLX(strtod("inf", NULL), strtod("inf", NULL)), CMPLX(strtod("inf", NULL), strtod("inf", NULL)), CMPLX(strtod("inf", NULL), strtod("inf", NULL)), 0);
	test(26, CMPLX(-12.34, strtod("-inf", NULL)), CMPLX(strtod("inf", NULL), strtod("-inf", NULL)), CMPLX(strtod("inf", NULL), strtod("-inf", NULL)), CMPLX(strtod("inf", NULL), strtod("-inf", NULL)), 0);
	test(27, CMPLX(nan(""), strtod("-inf", NULL)), CMPLX(nan(""), strtod("inf", NULL)), CMPLX(nan(""), strtod("inf", NULL)), CMPLX(nan(""), strtod("inf", NULL)), 0 | MF_ANYSIGN2);
	test(28, CMPLX(strtod("inf", NULL), strtod("-inf", NULL)), CMPLX(nan(""), strtod("inf", NULL)), CMPLX(nan(""), strtod("inf", NULL)), CMPLX(nan(""), strtod("inf", NULL)), 0 | MF_ANYSIGN2);
	test(29, CMPLX(strtod("-inf", NULL), strtod("-inf", NULL)), CMPLX(nan(""), strtod("inf", NULL)), CMPLX(nan(""), strtod("inf", NULL)), CMPLX(nan(""), strtod("inf", NULL)), 0 | MF_ANYSIGN2);
	test(30, CMPLX(0.0, strtod("-inf", NULL)), CMPLX(-0x0.0000000000001p-1022, strtod("-inf", NULL)), CMPLX(0x0.0p+0, strtod("-inf", NULL)), CMPLX(0x0.0000000000001p-1022, strtod("-inf", NULL)), 0);
	test(31, CMPLX(90.01, 0.0), CMPLX(0x1.c768c8574930cp-1, -0x0.0000000000001p-1022), CMPLX(0x1.c768c8574930dp-1, -0x0.0p+0), CMPLX(0x1.c768c8574930ep-1, 0x0.0000000000001p-1022), 0);
	test(32, CMPLX(-12.34, 0.0), CMPLX(0x1.cba85cb1eb4b8p-3, -0x0.0000000000001p-1022), CMPLX(0x1.cba85cb1eb4b9p-3, 0x0.0p+0), CMPLX(0x1.cba85cb1eb4bap-3, 0x0.0000000000001p-1022), 0);
	test(33, CMPLX(nan(""), 0.0), CMPLX(nan(""), -0x0.0000000000001p-1022), CMPLX(nan(""), 0x0.0p+0), CMPLX(nan(""), 0x0.0000000000001p-1022), 0);
	test(34, CMPLX(strtod("inf", NULL), 0.0), CMPLX(nan(""), -0x0.0000000000001p-1022), CMPLX(nan(""), 0x0.0p+0), CMPLX(nan(""), 0x0.0000000000001p-1022), 0);
	test(35, CMPLX(strtod("-inf", NULL), 0.0), CMPLX(nan(""), -0x0.0000000000001p-1022), CMPLX(nan(""), 0x0.0p+0), CMPLX(nan(""), 0x0.0000000000001p-1022), 0);
	test(36, CMPLX(0.0, 0.0), CMPLX(-0x0.0000000000001p-1022, -0x0.0000000000001p-1022), CMPLX(0x0.0p+0, 0x0.0p+0), CMPLX(0x0.0000000000001p-1022, 0x0.0000000000001p-1022), 0);
	return imprecise;
